// Default capsule shape
Label("Desert", systemImage: "sun.max.fill")
    .padding()
    .glassEffect()

// Custom shape
Label("Desert", systemImage: "sun.max.fill")
    .padding()
    .glassEffect(in: .rect(cornerRadius: 16))

// Tinted (use to convey meaning, not decoration)
Label("Desert", systemImage: "sun.max.fill")
    .padding()
    .glassEffect(.regular.tint(.green))

// Interactive — enables bounce/shimmer on press (iOS primarily; noop on macOS)
Label("Desert", systemImage: "sun.max.fill")
    .padding()
    .glassEffect(.regular.interactive())

// Conditional disable
MyView()
    .glassEffect(.regular, in: Capsule(), isEnabled: condition)

