// With morphing transitions via glassEffectID:
@Namespace private var glassNS

GlassEffectContainer {
    VStack {
        if isExpanded {
            ForEach(items) { item in
                ItemRow(item: item)
                    .glassEffect()
                    .glassEffectID(item.id, in: glassNS)
            }
        }
        ToggleButton()
            .buttonStyle(.glass)
            .glassEffectID("toggle", in: glassNS)
    }
}
// Views with matching IDs morph fluidly when they appear/disappear.

// Assigns a stable identity to a glass view so SwiftUI can
// animate shape morphing transitions between it and other glass
// views sharing the same namespace. Analogous to
// matchedGeometryEffect but wired into the glass rendering path.
//
// func glassEffectID<ID: Hashable>(_ id: ID, in namespace: Namespace.ID) -> some View

@Namespace private var ns
@State private var expanded = false

GlassEffectContainer {
    withAnimation(.spring()) {
        if expanded {
            LargeCard()
                .glassEffect(in: RoundedRectangle(cornerRadius: 20))
                .glassEffectID("card", in: ns)
        } else {
            SmallPill()
                .glassEffect()
                .glassEffectID("card", in: ns)
        }
    }
}
.onTapGesture { expanded.toggle() }

