// Lets a view's background visually bleed beyond its frame bounds
// into adjacent regions (behind toolbars, sidebars, navigation bars).
// Used for hero images or tinted backgrounds that should fill
// the full width behind an inset sidebar or scroll edge.
// Does NOT affect layout or hit-testing.

struct LandmarkDetail: View {
    var body: some View {
        ScrollView {
            VStack {
                Image("heroBackground")
                    .resizable()
                    .aspectRatio(contentMode: .fill)
                    .backgroundExtensionEffect()  // mirrors+blurs outside safe area
                ContentBody()
            }
        }
    }
}

@main
struct MyApp: App {
    var body: some Scene {
        MenuBarExtra {
            AppMenuView()
                // Frame on the root view drives the popover panel size.
                // No explicit API for window dimensions; use .frame().
                .frame(width: 320, height: 480)
        } label: {
            // Use Label or Image; SF Symbols are auto template images.
            Label("My App", systemImage: "menubar.arrow.up.rectangle")
        }
        .menuBarExtraStyle(.window)   // rich SwiftUI content
    }
}

// Programmatic dismiss from within the popover content:
struct AppMenuView: View {
    @Environment(\.dismiss) private var dismiss
    var body: some View {
        Button("Quit") {
            dismiss()   // closes the popover panel
            NSApplication.shared.terminate(nil)
        }
    }
}

// Programmatic toggle from app state (isInserted binding):
struct MyApp: App {
    @State private var isShown = true
    var body: some Scene {
        MenuBarExtra(isInserted: $isShown) {
            ContentView()
        } label: {
            Image(systemName: "star")
        }
    }
}

// The .window style renders a borderless NSPanel.
// macOS 13-25: the panel has NO automatic material background.
//   You must add one yourself:
struct PopoverContent: View {
    var body: some View {
        VStack { /* ... */ }
            .frame(width: 320, height: 400)
            .background(.regularMaterial)   // macOS 13-25 pattern
    }
}

// macOS 26 Liquid Glass approach:
// The system does NOT automatically apply a Liquid Glass background
// to a .window MenuBarExtra panel the way it does for sheets/toolbars.
// Apply glass explicitly to chrome elements; let content stay clear:
struct PopoverContentMacOS26: View {
    var body: some View {
        ZStack {
            // Full-window glass backdrop (navigation chrome layer)
            Rectangle()
                .glassEffect(in: Rectangle())
                .ignoresSafeArea()
            // Content sits above
            VStack { /* ... */ }
        }
        .frame(width: 320, height: 400)
    }
}

// Adaptive fallback:
struct AdaptivePopover: View {
    var body: some View {
        Group {
            if #available(macOS 26.0, *) {
                ContentBody()
                    .background { Rectangle().glassEffect(in: Rectangle()) }
            } else {
                ContentBody()
                    .background(.regularMaterial)
            }
        }
        .frame(width: 320, height: 400)
    }
}

// Pattern 1: Timer runs only while popover is open.
// onAppear/onDisappear are called reliably for .window style.
import Combine

struct PopoverView: View {
    @State private var timerSubscription: AnyCancellable?
    @State private var data: String = ""

    var body: some View {
        Text(data)
            .onAppear {
                timerSubscription = Timer.publish(every: 5, on: .main, in: .common)
                    .autoconnect()
                    .sink { _ in refresh() }
                refresh()
            }
            .onDisappear {
                timerSubscription?.cancel()
            }
    }

    func refresh() { data = fetchData() }
}

// Pattern 2: Background polling always on; popover reads @Observable model.
@Observable final class AppState {
    var data: String = ""
    private var timer: Timer?

    func startPolling() {
        timer = Timer.scheduledTimer(withTimeInterval: 30, repeats: true) { _ in
            Task { @MainActor in self.data = await fetchData() }
        }
    }
}

// Pattern 3 (macOS 13.3+): Use .task(id:) for async refresh on open:
struct PopoverView: View {
    @State private var isActive = false
    var body: some View {
        ContentView()
            .task(id: isActive) {
                guard isActive else { return }
                while !Task.isCancelled {
                    await refresh()
                    try? await Task.sleep(for: .seconds(10))
                }
            }
            .onAppear { isActive = true }
            .onDisappear { isActive = false }
    }
}

import ServiceManagement

// Register:
try SMAppService.mainApp.register()

// Unregister:
try SMAppService.mainApp.unregister()

// Read status:
switch SMAppService.mainApp.status {
case .enabled:          print("Will launch at login")
case .requiresApproval: SMAppService.openSystemSettingsLoginItems()
case .notRegistered:    break
case .notFound:         break
@unknown default:       break
}

// SwiftUI toggle:
struct LaunchAtLoginToggle: View {
    @State private var enabled = SMAppService.mainApp.status == .enabled
    var body: some View {
        Toggle("Launch at Login", isOn: $enabled)
            .onChange(of: enabled) { _, newValue in
                do {
                    if newValue { try SMAppService.mainApp.register() }
                    else        { try SMAppService.mainApp.unregister() }
                } catch {
                    enabled = (SMAppService.mainApp.status == .enabled)
                }
            }
    }
}

// No entitlement required for mainApp.
// User can override in System Settings > General > Login Items.

